/*
 * @ignore
 * @method
 * @name limitless#parseOrderSide
 * @description maps an order side string to the CCXT unified side vocabulary
 * @param {string} side the raw limitless order side
 * @returns {string} the unified order side
 */
    pub fn parse_order_side(&self, mut side: Value) -> Value {
        let mut sides: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("BUY".to_string(), Value::Str("buy".to_string()));
                m.insert("SELL".to_string(), Value::Str("sell".to_string()));
                m.insert("0".to_string(), Value::Str("buy".to_string()));
                m.insert("1".to_string(), Value::Str("sell".to_string()));
            m
        });
        return self.safe_string(sides.clone(), side.clone(), &[side.clone()]);

    Value::Null
}

    pub fn apply_scale(&self, mut amount: Value, optional_args: &[Value]) -> Value {
        let mut multiply = get_arg(optional_args, 0, Value::Bool(false));
        let mut decimals: Value = self.safe_integer_k(self.options.clone(), "usdcDecimals", &[Value::Int(6)]);
        let mut scale: Value = self.number_to_string(crate::runtime::Math::pow(&Value::Int(10), &decimals));
        if is_true(&multiply) {
            return crate::precise::Precise::stringMul(&amount, &scale);
        }  else {
            return crate::precise::Precise::stringDiv(&amount, &scale);
        }

    Value::Null
}

    pub fn parse_account(&self, mut account: Value) -> Value {
        let mut accountId: Value = self.safe_string_k(account.clone(), "id", &[]);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), accountId.clone());
        m.insert("type".to_string(), Value::Null);
        m.insert("code".to_string(), Value::Null);
        m.insert("info".to_string(), account.clone());
    m
});

    Value::Null
}

